+    pub enum EvidenceValidationError {
+        PosteriorNotNormalized {
+            sum: f64,
+        },
+        PosteriorEmpty,
+        InvalidPosteriorProbability {
+            index: usize,
+            value: f64,
+        },
+        InvalidExpectedLoss {
+            action: String,
+            value: f64,
+        },
+        CalibrationOutOfRange {
+            value: f64,
+        },
+        NegativeExpectedLoss {
+            action: String,
+            value: f64,
+        },
+        NegativeChosenExpectedLoss {
+            value: f64,
+        },
